"""sklearn.feature_extraction — Text and dict feature extraction."""
import numpy as np
import re
from collections import Counter
from sklearn.base import BaseEstimator, TransformerMixin


class DictVectorizer(BaseEstimator, TransformerMixin):
    """Transforms lists of feature-value dicts into numpy arrays.

    Parameters
    ----------
    sparse : bool, default=False
        Ignored (always returns dense arrays).
    sort : bool, default=True
    """

    def __init__(self, *, dtype=None, separator='=', sparse=False, sort=True):
        self.dtype = dtype
        self.separator = separator
        self.sparse = sparse
        self.sort = sort

    def fit(self, X, y=None):
        feature_names = set()
        for d in X:
            feature_names.update(d.keys())
        self.feature_names_ = sorted(feature_names) if self.sort else list(feature_names)
        self.vocabulary_ = {f: i for i, f in enumerate(self.feature_names_)}
        return self

    def transform(self, X):
        result = np.zeros((len(X), len(self.feature_names_)))
        for i, d in enumerate(X):
            for k, v in d.items():
                if k in self.vocabulary_:
                    result[i, self.vocabulary_[k]] = v
        return result

    def get_feature_names_out(self):
        return np.array(self.feature_names_)


class CountVectorizer(BaseEstimator, TransformerMixin):
    """Convert a collection of text documents to a matrix of token counts.

    Parameters
    ----------
    max_features : int or None, default=None
    stop_words : list or None, default=None
    min_df : int, default=1
    max_df : float, default=1.0
    ngram_range : tuple, default=(1, 1)
    lowercase : bool, default=True
    token_pattern : str, default=r'(?u)\\b\\w\\w+\\b'
    """

    def __init__(self, *, input='content', encoding='utf-8',
                 decode_error='strict', strip_accents=None, lowercase=True,
                 preprocessor=None, tokenizer=None, stop_words=None,
                 token_pattern=r'(?u)\b\w\w+\b', ngram_range=(1, 1),
                 analyzer='word', max_df=1.0, min_df=1, max_features=None,
                 vocabulary=None, binary=False, dtype=None):
        self.input = input
        self.encoding = encoding
        self.decode_error = decode_error
        self.strip_accents = strip_accents
        self.lowercase = lowercase
        self.preprocessor = preprocessor
        self.tokenizer = tokenizer
        self.stop_words = stop_words
        self.token_pattern = token_pattern
        self.ngram_range = ngram_range
        self.analyzer = analyzer
        self.max_df = max_df
        self.min_df = min_df
        self.max_features = max_features
        self.vocabulary = vocabulary
        self.binary = binary
        self.dtype = dtype

    def _tokenize(self, doc):
        if self.lowercase:
            doc = doc.lower()
        tokens = re.findall(self.token_pattern, doc)
        if self.stop_words:
            sw = set(self.stop_words)
            tokens = [t for t in tokens if t not in sw]
        # n-grams
        min_n, max_n = self.ngram_range
        if max_n == 1:
            return tokens
        ngrams = []
        for n in range(min_n, max_n + 1):
            for i in range(len(tokens) - n + 1):
                ngrams.append(' '.join(tokens[i:i + n]))
        return ngrams

    def fit(self, raw_documents, y=None):
        n_docs = len(raw_documents)
        df = Counter()
        tf_all = Counter()
        for doc in raw_documents:
            tokens = self._tokenize(doc)
            tf_all.update(tokens)
            df.update(set(tokens))

        # Filter by doc frequency
        min_df = self.min_df if isinstance(self.min_df, int) else int(self.min_df * n_docs)
        max_df = self.max_df if isinstance(self.max_df, float) and self.max_df <= 1.0 \
            else self.max_df
        if isinstance(max_df, float):
            max_df = int(max_df * n_docs)

        vocab = {w for w, c in df.items() if min_df <= c <= max_df}

        # Sort by frequency, then alphabetically
        words = sorted(vocab)
        if self.max_features:
            words = sorted(words, key=lambda w: -tf_all[w])[:self.max_features]
            words = sorted(words)

        self.vocabulary_ = {w: i for i, w in enumerate(words)}
        return self

    def transform(self, raw_documents):
        result = np.zeros((len(raw_documents), len(self.vocabulary_)))
        for i, doc in enumerate(raw_documents):
            tokens = self._tokenize(doc)
            for t in tokens:
                if t in self.vocabulary_:
                    result[i, self.vocabulary_[t]] += 1
        return result

    def get_feature_names_out(self):
        words = sorted(self.vocabulary_, key=self.vocabulary_.get)
        return np.array(words)


class TfidfTransformer(BaseEstimator, TransformerMixin):
    """Transform a count matrix to a TF-IDF representation.

    Parameters
    ----------
    norm : str, default='l2'
    use_idf : bool, default=True
    smooth_idf : bool, default=True
    sublinear_tf : bool, default=False
    """

    def __init__(self, norm='l2', use_idf=True, smooth_idf=True, sublinear_tf=False):
        self.norm = norm
        self.use_idf = use_idf
        self.smooth_idf = smooth_idf
        self.sublinear_tf = sublinear_tf

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if self.use_idf:
            n_docs = X.shape[0]
            df = np.sum(X > 0, axis=0)
            if self.smooth_idf:
                self.idf_ = np.log((1 + n_docs) / (1 + df)) + 1
            else:
                self.idf_ = np.log(n_docs / (df + 1e-15)) + 1
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float).copy()
        if self.sublinear_tf:
            mask = X > 0
            X[mask] = 1 + np.log(X[mask])
        if self.use_idf:
            X = X * self.idf_
        if self.norm == 'l2':
            norms = np.sqrt(np.sum(X ** 2, axis=1, keepdims=True))
            norms[norms == 0] = 1
            X = X / norms
        elif self.norm == 'l1':
            norms = np.sum(np.abs(X), axis=1, keepdims=True)
            norms[norms == 0] = 1
            X = X / norms
        return X


class TfidfVectorizer(BaseEstimator, TransformerMixin):
    """Convert text to TF-IDF features (combines CountVectorizer + TfidfTransformer).

    Parameters
    ----------
    max_features : int or None, default=None
    stop_words : list or None, default=None
    min_df : int, default=1
    max_df : float, default=1.0
    ngram_range : tuple, default=(1, 1)
    norm : str, default='l2'
    use_idf : bool, default=True
    smooth_idf : bool, default=True
    sublinear_tf : bool, default=False
    lowercase : bool, default=True
    """

    def __init__(self, *, input='content', encoding='utf-8',
                 decode_error='strict', strip_accents=None, lowercase=True,
                 preprocessor=None, tokenizer=None, analyzer='word',
                 stop_words=None, token_pattern=r'(?u)\b\w\w+\b',
                 ngram_range=(1, 1), max_df=1.0, min_df=1,
                 max_features=None, vocabulary=None, binary=False,
                 dtype=None, norm='l2', use_idf=True, smooth_idf=True,
                 sublinear_tf=False):
        self.input = input
        self.encoding = encoding
        self.decode_error = decode_error
        self.strip_accents = strip_accents
        self.lowercase = lowercase
        self.preprocessor = preprocessor
        self.tokenizer = tokenizer
        self.analyzer = analyzer
        self.stop_words = stop_words
        self.token_pattern = token_pattern
        self.ngram_range = ngram_range
        self.max_df = max_df
        self.min_df = min_df
        self.max_features = max_features
        self.vocabulary = vocabulary
        self.binary = binary
        self.dtype = dtype
        self.norm = norm
        self.use_idf = use_idf
        self.smooth_idf = smooth_idf
        self.sublinear_tf = sublinear_tf

    def fit(self, raw_documents, y=None):
        self._count = CountVectorizer(
            max_features=self.max_features, stop_words=self.stop_words,
            min_df=self.min_df, max_df=self.max_df,
            ngram_range=self.ngram_range, lowercase=self.lowercase)
        counts = self._count.fit_transform(raw_documents)
        self._tfidf = TfidfTransformer(
            norm=self.norm, use_idf=self.use_idf,
            smooth_idf=self.smooth_idf, sublinear_tf=self.sublinear_tf)
        self._tfidf.fit(counts)
        self.vocabulary_ = self._count.vocabulary_
        return self

    def transform(self, raw_documents):
        counts = self._count.transform(raw_documents)
        return self._tfidf.transform(counts)

    def get_feature_names_out(self):
        return self._count.get_feature_names_out()
